const requestBody = $json.body || $json;
const headers = $json.headers || {};
const expectedToken = $env.SANKHYA_PCP_TOKEN || '';
const receivedToken = headers['x-pcp-token'] || headers['X-Pcp-Token'] || headers['X-PCP-Token'] || '';
const authorized = !expectedToken || receivedToken === expectedToken;
const payload = requestBody;
const meta = {
  authorized,
  webhook_path: 'pcp/sankhya-romaneio-shadow',
  headers,
  query: $json.query || {},
  params: $json.params || {},
  remote_addr: headers['x-forwarded-for'] || headers['x-real-ip'] || ''
};
return [{ json: { authorized, payload, meta } }];

const esc = (value) => JSON.stringify(value ?? {}).replace(/'/g, "''");
let sql;
if ($json.authorized) {
  sql = `select ops.ingest_romaneio_event_payload(\n  'romaneio_sankhya_webhook',\n  '${esc($json.payload)}'::jsonb,\n  '${esc($json.meta)}'::jsonb\n) as result;`;
} else {
  sql = `select jsonb_build_object('status','unauthorized','processed',false,'message','Token invalido ou ausente') as result;`;
}
return [{ json: { ...$json, sql_query: sql } }];

const row = $json || {};
let result = row.result ?? row;
if (typeof result === 'string') {
  try {
    result = JSON.parse(result);
  } catch (error) {
    result = { status: 'unknown', raw_result: row.result };
  }
}
const ok = ['processed', 'duplicate_ignored'].includes(result.status);
return [{
  json: {
    ok,
    workflow: 'PCP | 11 | Sankhya | Romaneio Webhook',
    mode: 'shadow',
    ...result
  }
}];
